{"code": "import pandas as pd
import re

books = env['data_1']
reviews = env['data_2']

# Extract year from details
def extract_year(details):
    match = re.search(r'\b(19|20)\d{2}\b', details)
    if match:
        return int(match.group(0))
    return None

for b in books:
    b['year'] = extract_year(b['details'])
    if b['year']:
        b['decade'] = f"{b['year'] // 10 * 10}s"
    else:
        b['decade'] = None
    # Normalize book_id to match purchase_id
    b['norm_id'] = b['book_id'].replace('bookid_', '')

for r in reviews:
    r['norm_id'] = r['purchase_id'].replace('purchaseid_', '')

df_books = pd.DataFrame(books)
df_reviews = pd.DataFrame(reviews)

df = pd.merge(df_reviews, df_books, on='norm_id', how='inner')

# Group by decade
decade_stats = df.groupby('decade').agg(
    avg_rating=('rating', 'mean'),
    distinct_books=('book_id', 'nunique')
).reset_index()

print(decade_stats)

valid_decades = decade_stats[decade_stats['distinct_books'] >= 10]
if not valid_decades.empty:
    best_decade = valid_decades.loc[valid_decades['avg_rating'].idxmax()]
    print("Best decade:", best_decade['decade'])
else:
    print("No decade with at least 10 distinct books.")
"}
